68	      action: 'action1',
69	      entities: ['entity1'],
70	      type: 'MIMETYPE',
71	      uri: 'key={true,true,false}',
72	      parameters:
73	      {
74	        mykey0: 2222,
75	        mykey1: [1, 2, 3],
76	        mykey2: '[1, 2, 3]',
77	        mykey3: 'ssssssssssssssssssssssssss',
