83	  ],
84	  actionType: wantAgent.OperationType.START_ABILITY,
85	  requestCode: 0,
86	  wantAgentFlags: [wantAgent.WantAgentFlags.UPDATE_PRESENT_FLAG]
87	};
88	
89	// getWantAgent回调
90	function getWantAgentCallback(err: BusinessError, data: WantAgent) {
91	  if (err.code) {
92	    console.error(`getWantAgent failed, code: ${JSON.stringify(err.code)}, message: ${JSON.stringify(err.message)}`);
93	  } else {
94	    wantAgentData = data;
95	  }
96	}
97	
